	public void SetStats(int placement, int kills, int deaths, int damageDealt, int damageTaken, int survivalTime, Dictionary<string, int> weaponDamage, int coinsEarned, int ratingChange, int currentRating, int newRating, int newCoins, string? killerUsername = null, string killerRank = "N", List<BattlePassTaskInfo>? completedTasks = null, int xpGained = 0, int playerLevel = 1, int playerXp = 0, int playerMaxXp = 100, bool isPartyMode = false, List<PubgPartyStatsEntry>? partyStats = null, BattlePassStateMessage? battlePassState = null, int? previousPlayerLevel = null, int? previousPlayerXp = null, int? previousPlayerMaxXp = null)
	{
		_targetPlacement = Math.Max(1, placement);
		_targetKills = Math.Max(0, kills);
		_targetDeaths = Math.Max(0, deaths);
		_targetDamageDealt = Math.Max(0, damageDealt);
		_targetDamageTaken = Math.Max(0, damageTaken);
		_targetSurvivalTime = Math.Max(0, survivalTime);
		_targetCoinsEarned = coinsEarned;
		_targetCurrentCoins = newCoins - coinsEarned;
		_targetNewCoins = newCoins;
		_targetRatingChange = ratingChange;
		_targetCurrentRating = currentRating;
		_targetNewRating = newRating;
		_targetPlayerLevel = Math.Max(1, playerLevel);
		_targetPlayerMaxXp = Math.Max(1, playerMaxXp);
		_targetPlayerXp = Math.Clamp(playerXp, 0, _targetPlayerMaxXp);
		ResolveLevelAnimationStart(previousPlayerLevel, previousPlayerXp, previousPlayerMaxXp);
		ConfigureLevelDeltaLabel();
		ConfigureHero(_targetPlacement);
		if (!string.IsNullOrWhiteSpace(killerUsername) && _targetPlacement > 1)
		{
