	private void ShowBattlePassData(BattlePassStateMessage? state, List<BattlePassTaskInfo>? fallbackTasks, int xpGained, bool animateGain)
	{
		((Control)BpTasksContainer).RemoveAllChildren();
		((Control)ClaimXpButton).Visible = false;
		if (state != null)
		{
			_battlePassState = state;
			BpSeasonLabel.Text = Loc.GetString("pubg-bp-season", new(string, object)[1] { ("name", state.SeasonName) });
			PopulateBattlePassTasksFromState(state);
			((Control)BpStateLabel).Visible = false;
			if (animateGain && xpGained > 0)
			{
				StartBattlePassAnimation(state, xpGained);
				return;
			}
			_battlePassAnimating = false;
			(int, int, int) tuple = ResolveBattlePassProgress(state, state.CurrentXp);
			SetBattlePassProgressDisplay(tuple.Item1, tuple.Item2, tuple.Item3);
			SetBattlePassGainLabel(xpGained);
		}
		else
		{
			_battlePassAnimating = false;
			BpSeasonLabel.Text = Loc.GetString("pubg-stats-bp-season-placeholder");
			SetBattlePassProgressDisplay(1, 0, 100);
			SetBattlePassGainLabel(xpGained);
			PopulateBattlePassTasksFallback(fallbackTasks);
			BpStateLabel.Text = ((fallbackTasks != null && fallbackTasks.Count > 0) ? Loc.GetString("pubg-stats-bp-state-fallback") : Loc.GetString("pubg-stats-bp-loading"));
			((Control)BpStateLabel).Visible = true;
		}
	}

	private void PopulateBattlePassTasksFromState(BattlePassStateMessage state)
	{
		List<BattlePassTaskInfo> list = (from task in state.Tasks
			where !task.IsSkipped && task.IsCompleted && !task.XpClaimed
			orderby task.Slot
			select task).Take(5).ToList();
		List<BattlePassTaskInfo> list2 = ((list.Count > 0) ? list : (from task in state.Tasks
			where !task.IsSkipped
			orderby (task.TargetValue <= 0) ? 0f : ((float)task.Progress / (float)task.TargetValue) descending, task.Slot
			select task).Take(5).ToList());
		if (list2.Count == 0)
		{
			AddBattlePassEmptyRow();
			return;
		}
		foreach (BattlePassTaskInfo item in list2)
		{
			PanelContainer val = CreateBattlePassTaskRow(item, item.IsCompleted && !item.XpClaimed);
			((Control)BpTasksContainer).AddChild((Control)(object)val);
		}
	}

	private void PopulateBattlePassTasksFallback(List<BattlePassTaskInfo>? tasks)
	{
		if (tasks == null || tasks.Count == 0)
		{
			AddBattlePassEmptyRow();
			return;
		}
		foreach (BattlePassTaskInfo item in tasks.Take(5))
		{
			PanelContainer val = CreateBattlePassTaskRow(item, item.IsCompleted && !item.XpClaimed);
			((Control)BpTasksContainer).AddChild((Control)(object)val);
		}
	}

