	private void StartBattlePassAnimation(BattlePassStateMessage state, int gainXp)
	{
		_battlePassAnimationTime = 0f;
		_battlePassAnimating = true;
		_battlePassTargetGainXp = Math.Max(0, gainXp);
		_battlePassTargetTotalXp = Math.Max(0, state.CurrentXp);
		_battlePassStartTotalXp = Math.Max(0, _battlePassTargetTotalXp - _battlePassTargetGainXp);
		SetBattlePassGainLabel(0);
		(int, int, int) tuple = ResolveBattlePassProgress(state, _battlePassStartTotalXp);
		SetBattlePassProgressDisplay(tuple.Item1, tuple.Item2, tuple.Item3);
	}

	private void UpdateBattlePassAnimation(float deltaSeconds)
	{
		if (_battlePassState == null)
		{
			_battlePassAnimating = false;
			return;
		}
		_battlePassAnimationTime += deltaSeconds;
		float num = Math.Clamp(_battlePassAnimationTime / 1.1f, 0f, 1f);
		float t = EaseOutCubic(num);
		int totalXp = LerpInt(_battlePassStartTotalXp, _battlePassTargetTotalXp, t);
		int battlePassGainLabel = LerpInt(0, _battlePassTargetGainXp, t);
		(int, int, int) tuple = ResolveBattlePassProgress(_battlePassState, totalXp);
		SetBattlePassProgressDisplay(tuple.Item1, tuple.Item2, tuple.Item3);
		SetBattlePassGainLabel(battlePassGainLabel);
		if (num >= 1f)
		{
			_battlePassAnimating = false;
			SetBattlePassGainLabel(_battlePassTargetGainXp);
		}
	}

	private void SetBattlePassGainLabel(int gainedXp)
	{
		if (gainedXp <= 0)
		{
			((Control)BpXpLabel).Visible = false;
			BpXpLabel.Text = string.Empty;
		}
		else
		{
			((Control)BpXpLabel).Visible = true;
			BpXpLabel.Text = Loc.GetString("pubg-stats-bp-xp-earned", new(string, object)[1] { ("xp", gainedXp) });
		}
	}

	private void SetBattlePassProgressDisplay(int level, int xpInLevel, int xpRequired)
	{
		int num = Math.Max(1, xpRequired);
		int num2 = Math.Clamp(xpInLevel, 0, num);
		BpLevelLabel.Text = Loc.GetString("pubg-bp-level", new(string, object)[1] { ("level", level) });
		((Range)BpProgressBar).MinValue = 0f;
		((Range)BpProgressBar).MaxValue = num;
		((Range)BpProgressBar).Value = num2;
		BpProgressTextLabel.Text = Loc.GetString("pubg-bp-xp", new(string, object)[2]
		{
			("current", num2),
			("required", num)
